### Unit Tests for Memoize Function

The following tests are written in pytest style to cover the happy path, edge cases, and error cases for the `memoize` function.

```python
import pytest
from your_module import memoize  # Replace 'your_module' with the actual module name

def test_memoize_happy_path():
    """Test memoize with a simple function."""
    @memoize
    def add(a, b):
        return a + b

    assert add(1, 2) == 3
    assert add(1, 2) == 3  # Second call should return cached result

def test_memoize_cache_hit():
    """Test that memoize caches results correctly."""
    @memoize
    def add(a, b):
        return a + b

    add(1, 2)
    assert add(1, 2) == 3  # Should return cached result

def test_memoize_cache_miss():
    """Test that memoize does not cache different inputs."""
    @memoize
    def add(a, b):
        return a + b

    assert add(1, 2) == 3
    assert add(2, 3) == 5  # Should not return cached result

def test_memoize_edge_case_empty_args():
    """Test memoize with a function that takes no arguments."""
    @memoize
    def constant():
        return 42

    assert constant() == 42
    assert constant() == 42  # Should return cached result

def test_memoize_edge_case_single_arg():
    """Test memoize with a function that takes a single argument."""
    @memoize
    def square(x):
        return x ** 2

    assert square(4) == 16
    assert square(4) == 16  # Should return cached result

def test_memoize_error_case_exception():
    """Test that memoize propagates exceptions."""
    @memoize
    def divide(a, b):
        if b == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return a / b

    with pytest.raises(ZeroDivisionError):
        divide(1, 0)
    with pytest.raises(ZeroDivisionError):
        divide(1, 0)  # Should raise exception again

def test_memoize_error_case_unhashable_args():
    """Test that memoize raises TypeError for unhashable arguments."""
    @memoize
    def identity(x):
        return x

    with pytest.raises(TypeError):
        identity([1, 2, 3])  # Lists are unhashable

def test_memoize_multiple_calls_with_same_args():
    """Test that memoize returns the same result for multiple calls with the same arguments."""
    call_count = 0
    @memoize
    def add(a, b):
        nonlocal call_count
        call_count += 1
        return a + b

    add(1, 2)
    add(1, 2)
    assert call_count == 1  # The function should be called only once

def test_memoize_multiple_calls_with_different_args():
    """Test that memoize returns different results for multiple calls with different arguments."""
    call_count = 0
    @memoize
    def add(a, b):
        nonlocal call_count
        call_count += 1
        return a + b

    add(1, 2)
    add(2, 3)
    assert call_count == 2  # The function should be called twice
```

These tests cover various scenarios, including:

* Happy path: Testing the `memoize` function with a simple function.
* Edge cases: Testing with a function that takes no arguments, a single argument, and different inputs.
* Error cases: Testing that `memoize` propagates exceptions and raises `TypeError` for unhashable arguments.
* Multiple calls: Testing that `memoize` returns the same result for multiple calls with the same arguments and different results for multiple calls with different arguments.
